const items = $('AI Agent').first().json.output;

// ─── Sub-section parser (e.g. CRITICAL / HIGH / MEDIUM / LOW blocks) ───────
function parseSubSections(content) {
  const result = {};
  let currentKey = null;
  let currentItems = [];

  for (const line of content.split('\n')) {
    const trimmed = line.trim();
    if (!trimmed) continue;

    // Header = ALL-CAPS word(s) followed by a colon, nothing else on the line
    const headerMatch = trimmed.match(/^([A-Z][A-Z\s]{1,30}):\s*$/);
    if (headerMatch) {
      if (currentKey !== null) result[currentKey.toLowerCase()] = currentItems;
      currentKey = headerMatch[1].trim();
      currentItems = [];
    } else if (currentKey !== null) {
      // Numbered item  →  "1. Some text"
      const numberedMatch = trimmed.match(/^\d+\.\s+(.+)/);
      if (numberedMatch) currentItems.push(numberedMatch[1]);
    }
  }

  if (currentKey !== null) result[currentKey.toLowerCase()] = currentItems;
  return Object.keys(result).length > 0 ? result : null;
}

// ─── Generic content parser ──────────────────────────────────────────────────
function parseContent(content) {
  if (!content) return '';

  // 1. Try sub-section blocks first (ALL-CAPS headings)
  const subSections = parseSubSections(content);
  if (subSections) return subSections;

  // 2. Numbered list  →  array
  const numbered = content
    .split('\n')
    .map(l => l.trim())
    .filter(l => /^\d+\.\s+/.test(l))
    .map(l => l.replace(/^\d+\.\s+/, ''));
  if (numbered.length > 0) return numbered;

  // 3. Bullet list  →  array
  const bullets = content
    .split('\n')
    .map(l => l.trim())
    .filter(l => /^[•\-\*]\s/.test(l))
    .map(l => l.replace(/^[•\-\*]\s*/, ''));
  if (bullets.length > 0) return bullets;

  // 4. Plain text — collapse extra whitespace
  return content.replace(/[ \t]+/g, ' ').replace(/\n{2,}/g, '\n').trim();
}

// ─── Master parser ───────────────────────────────────────────────────────────
function parseAIOutput(rawText) {
  const result = {};

  // Normalize literal "\n" strings AND strip trailing whitespace per line
  const text = rawText
    .replace(/\\n/g, '\n')          // literal \n → real newline
    .replace(/[ \t]+$/gm, '');      // trailing spaces per line

  /*
    Matches section markers in these formats:
      **--Title--**
      **--Bold title: Title--**
      **--Title--**   (no ** wrappers, fallback)
  */
  const sectionRegex = /(?:\*\*)?--([\s\S]*?)--(?:\*\*)?/g;

  const sections = [];
  let m;
  while ((m = sectionRegex.exec(text)) !== null) {
    sections.push({
      title: m[1].trim(),
      index: m.index,
      endIndex: m.index + m[0].length
    });
  }

  sections.forEach((section, i) => {
    const nextIndex = sections[i + 1]?.index ?? text.length;
    const content = text.slice(section.endIndex, nextIndex).trim();

    // ── Derive clean title ─────────────────────────────────────────────────
    let rawTitle = section.title;

    // Strip "Bold title: " prefix  →  "Bold title: UX Issues"  →  "UX Issues"
    rawTitle = rawTitle.replace(/^Bold\s+title:\s*/i, '').trim();

    // Build snake_case key
    const key = rawTitle
      .toLowerCase()
      .replace(/[^\w\s]/g, '')      // remove punctuation
      .replace(/\s+/g, '_')         // spaces → underscore
      .replace(/_{2,}/g, '_')       // collapse double underscores
      .replace(/^_|_$/g, '');       // trim leading/trailing underscores

    if (!key) return;               // skip empty/malformed markers

    result[key] = parseContent(content);
  });

  return result;
}

// ─── n8n entry point ─────────────────────────────────────────────────────────
return items.map(item => {
  const text = item.json.output || item.json.text || '';
  return {
    json: {
      parsed: parseAIOutput(text)
    }
  };
});

