const output = $input.first().json.output || "";

// Normalize text
const text = output.trim();

// Required sections in strict order
const sections = [
  "--Overview--",
  "--ux_issues--",
  "--ui_issues--",
  "--titles_audit--",
  "--photos_audit--",
  "--descriptions_audit--",
  "--categories_audit--",
  "--recommanded_fixes--",
  "--final_assessment--"
];

// Initialize
let isValid = true;
let issues = [];



// Rule 2: No intro or extra text before first section
if (!text.startsWith("--Overview--")) {
  isValid = false;
  issues.push("CRITICAL: Output does not start with --Overview--.");
}

// Rule 3: Check all sections exist and in order
let lastIndex = -1;
sections.forEach((section) => {
  const index = text.indexOf(section);
  if (index === -1) {
    isValid = false;
    issues.push(`CRITICAL: Missing section ${section}.`);
  } else if (index < lastIndex) {
    isValid = false;
    issues.push(`CRITICAL: Section ${section} is out of order.`);
  }
  lastIndex = index;
});

// Rule 4: Ensure ONLY these sections exist
const extraSectionPattern = /--[a-zA-Z_]+--/g;
const foundSections = text.match(extraSectionPattern) || [];

foundSections.forEach(sec => {
  if (!sections.includes(sec)) {
    isValid = false;
    issues.push(`HIGH: Unexpected section detected ${sec}.`);
  }
});


// Rule 6: Validate recommended_fixes structure
const recSectionMatch = text.match(/--recommanded_fixes--([\s\S]*?)--final_assessment--/);
if (recSectionMatch) {
  const recText = recSectionMatch[1];

  const requiredGroups = ["CRITICAL", "HIGH", "MEDIUM", "LOW"];
  requiredGroups.forEach(group => {
    if (!recText.includes(group)) {
      isValid = false;
      issues.push(`CRITICAL: Missing ${group} group in recommended_fixes.`);
    }
  });

  if (!/\d+\./.test(recText)) {
    isValid = false;
    issues.push("HIGH: recommended_fixes must contain numbered items.");
  }
} else {
  isValid = false;
  issues.push("CRITICAL: recommended_fixes section structure invalid.");
}

// Rule 7: Empty sections must contain fallback sentence
sections.forEach(section => {
  const regex = new RegExp(`${section}([\\s\\S]*?)(?=--|$)`);
  const match = text.match(regex);

  if (match) {
    const content = match[1].trim();
    if (content === "") {
      isValid = false;
      issues.push(`MEDIUM: ${section} is empty without fallback sentence.`);
    }
  }
});

// Final result
return [{
  json: {
    valid: isValid,
    result: isValid ? "true" : "false",
    issues: isValid ? [] : issues
  }
}];

